    if (apname == null || user == null) return;
    UserFeatureAccessModule modules=UserFeatureAccessModule.configureUserAccessModule(session,apname,user);
    String path = request.getParameter("p"),
            sheetName = request.getParameter("sheet");
    NUIFormSet set = NUIFormSetInfo.loadBrowsingFormSet(session, apname, path, sheetName);
    if((modules == null || !modules.ifAllow(Const.FUNC_MASS_FILE_UPLOAD,set.getForm(),user)) && !user.ifApManager(apname)) return;

    int dataSize = 10000;
    try{
        int _paramDs = Integer.parseInt(request.getParameter("ds"));
        if(_paramDs < dataSize) dataSize = _paramDs;
    } catch (NumberFormatException e) {}
    int key = Encoder.parseInt(request.getParameter("key"));

    SXSSFWorkbook wb = new SXSSFWorkbook(500);
    Sheet sheet = wb.createSheet("Ragic");
    CellStyle headerCell = wb.createCellStyle();
    CellStyle dataCell = wb.createCellStyle();
    Font font = wb.createFont();
    Font boldFont = wb.createFont();

    sheet.setDisplayGridlines(false);
    sheet.setPrintGridlines(false);
    setDefaultFontName(font, bundle);
    setDefaultFontName(boldFont,bundle);
    boldFont.setBold(true);

    headerCell.setVerticalAlignment(VerticalAlignment.CENTER);
    headerCell.setFont(boldFont);
    headerCell.setAlignment(HorizontalAlignment.RIGHT);

    dataCell.setFont(font);
    dataCell.setVerticalAlignment(VerticalAlignment.CENTER);

    
    APIQuery aq = new APIQuery(apname, path, sheetName);
    aq.setUpdateMode();
    NUIForm form = aq.getForm();
    //do not use form.getUploadFileFields because you would also get st domain.
    List<CellInfo> uploadFields = new ArrayList<>();
    for (Map.Entry<CellLocation, CellInfo> e : form.getFields().entrySet()) {
        if (Const.FILE.equals(e.getValue().getType()) && form.isSingleCell(e.getKey())) {
            uploadFields.add(e.getValue());
        }
    }

    uploadFields.addAll(form.getGraphicFields());
    CellInfo firstCellInfo;
    int firstFieldDomainId;
    if(form.hasDomainId(key)){
        firstCellInfo = form.getCellInfoByDomainId(key);
        firstFieldDomainId = key;
    } else {
        firstCellInfo = form.getField(form.getRootLocation());
        firstFieldDomainId = firstCellInfo.getDomainId();
    }
    aq.addFetchDomains(firstFieldDomainId);

    // print header
    Row headerRow = sheet.createRow(0);
    headerRow.setHeightInPoints(20);
    Cell firstCell = headerRow.createCell(0);
    firstCell.setCellStyle(headerCell);
    firstCell.setCellValue(firstCellInfo.getValue());
    int cellIndex = 1;
    for(CellInfo uploadField : uploadFields){
        Cell cell = headerRow.createCell(cellIndex++);
        cell.setCellStyle(headerCell);
        cell.setCellValue(uploadField.getValue());
        aq.addFetchDomains(uploadField.getDomainId());
    }

